section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/breaking-change-deprecation-policy.json",
  "title": "Breaking Change Deprecation Policy",
  "type": "object",
  "required": [
    "artefact_id",
    "component_id",
    "current_version",
    "next_version",
    "deprecation_window_days",
    "removal_date",
    "migration_guide_ref",
    "consumer_teams",
    "opt_in_flag",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "component_id": {
      "type": "string",
      "description": "component_id",
      "minLength": 1
    },
    "current_version": {
      "type": "string",
      "description": "current_version",
      "minLength": 1
    },
    "next_version": {
      "type": "string",
      "description": "next_version",
      "minLength": 1
    },
    "deprecation_window_days": {
      "type": "number",
      "description": "deprecation_window_days (numeric)"
    },
    "removal_date": {
      "type": "string",
      "description": "removal_date (ISO-8601)",
      "format": "date-time"
    },
    "migration_guide_ref": {
      "type": "string",
      "description": "migration_guide_ref",
      "minLength": 1
    },
    "consumer_teams": {
      "type": "array",
      "description": "consumer_teams (array)",
      "minItems": 1
    },
    "opt_in_flag": {
      "type": "string",
      "description": "opt_in_flag",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
